    pub is_error: bool,
    pub teammate_id: String,
    pub teammate_color: String,
}

/// Classified message types.
#[derive(Debug, Clone)]
pub enum ClassifiedMsg {
    User(UserMsg),
    AI(AIMsg),
    System(SystemMsg),
    Teammate(TeammateMsg),
    Compact(CompactMsg),
    Hook(HookMsg),
}

#[derive(Debug, Clone)]
pub struct UserMsg {
